function Particles() {
  const dots = Array.from({ length: 28 }, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    size: Math.random() * 2.5 + 1,
    delay: Math.random() * 6,
    dur: Math.random() * 4 + 4,
    color: i % 2 === 0 ? "#ff2d78" : "#b400ff",
  }));

  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0, overflow: "hidden" }}>
      {dots.map((d) => (
        <div
          key={d.id}
          style={{
            position: "absolute",
            left: `${d.x}%`,
            top: `${d.y}%`,
            width: d.size,
            height: d.size,
            borderRadius: "50%",
            background: d.color,
            opacity: 0,
            animation: `twinkle ${d.dur}s ${d.delay}s infinite`,
            boxShadow: `0 0 ${d.size * 3}px ${d.color}`,
          }}
        />
      ))}
    </div>
  );
}

